// Validează input-ul pentru workflow-ul de traducere categorii.
// Input body: { marketplace: 'trendyol_ro', limit: 500 }
const body = $input.first().json.body || {};
let marketplace = String(body.marketplace || 'trendyol_ro').toLowerCase().trim();

// Accept și alias-uri scurte (trendyol -> trendyol_ro)
const alias = {
  'trendyol': 'trendyol_ro',
  'emag': 'emag_ro',
  'temu': 'temu_ro'
};
if (alias[marketplace]) marketplace = alias[marketplace];

let limit = parseInt(body.limit, 10);
if (!Number.isFinite(limit) || limit <= 0) limit = 500;
if (limit > 2000) limit = 2000;

return [{ json: { marketplace, limit } }];

const https = require('https');

// ─── CONFIGURARE API ────────────────────────────────────────────────────────
const GEMINI_API_KEY = 'PUNE_GEMINI_API_KEY_AICI';
const MODEL_PRIMARY  = 'gemini-3.1-flash-lite-preview';
const MODEL_FALLBACK = 'gemini-flash-latest';
// Rate limit: Gemini 3.1 Flash Lite = 900 RPM. Folosim ~75ms spacing = ~800 RPM efectiv.
const REQUEST_DELAY_MS = 75;
// ────────────────────────────────────────────────────────────────────────────

function httpsRequest(options, postBody) {
  return new Promise((resolve, reject) => {
    const req = https.request(options, res => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve({ status: res.statusCode, body: Buffer.concat(chunks) }));
    });
    req.on('error', reject);
    if (postBody) req.write(postBody);
    req.end();
  });
}

async function callGemini(model, reqBodyStr) {
  const res = await httpsRequest({
    hostname: 'generativelanguage.googleapis.com',
    path: `/v1beta/models/${model}:generateContent?key=${GEMINI_API_KEY}`,
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(reqBodyStr)
    }
  }, reqBodyStr);
  if (res.status >= 500) throw new Error(`HTTP ${res.status} from Gemini`);
  return res;
}

function extractText(geminiResponse) {
  try {
    const parsed = JSON.parse(geminiResponse.body.toString('utf8'));
    return parsed?.candidates?.[0]?.content?.parts?.[0]?.text || null;
  } catch (e) {
    return null;
  }
}

async function translateOne(categoryName) {
  const systemInstruction = `Traduci nume de categorii de e-commerce din engleză în română pentru căutare de utilizator.\n\nReguli stricte:\n1. Păstrează ierarhia dacă există (ex: "Home > Curtains" → "Casă > Perdele").\n2. NU traduce brand-uri, modele sau denumiri tehnice (USB-C, OLED, iPhone, etc).\n3. Traducerea trebuie să fie naturală, scurtă, folosind termeni uzuali de cumpărături.\n4. Dacă nu ești sigur de o traducere bună, copiază EXACT numele englezesc.\n5. Returnează DOAR JSON valid: {"name_ro": "<text>"}.\n6. NU oferi explicații, doar JSON.`;

  const userText = `Nume categorie (engleză): ${categoryName}`;

  const reqBody = {
    systemInstruction: { parts: [{ text: systemInstruction }] },
    contents: [{ role: 'user', parts: [{ text: userText }] }],
    generationConfig: {
      temperature: 0.1,
      responseMimeType: 'application/json',
      responseSchema: {
        type: 'object',
        properties: { name_ro: { type: 'string' } },
        required: ['name_ro']
      }
    }
  };
  const reqBodyStr = JSON.stringify(reqBody);

  let res;
  try {
    res = await callGemini(MODEL_PRIMARY, reqBodyStr);
  } catch (err) {
    try {
      res = await callGemini(MODEL_FALLBACK, reqBodyStr);
    } catch (err2) {
      return { ok: false, error: err2.message };
    }
  }

  const text = extractText(res);
  if (!text) return { ok: false, error: 'empty response' };
  try {
    const json = JSON.parse(text);
    if (json && typeof json.name_ro === 'string' && json.name_ro.trim()) {
      return { ok: true, name_ro: json.name_ro.trim() };
    }
  } catch (e) {
    return { ok: false, error: 'json parse: ' + e.message };
  }
  return { ok: false, error: 'invalid name_ro' };
}

const prep = $('Prepare Input').first().json;
const marketplace = prep.marketplace;

const rows = $input.all().map(i => i.json).filter(r => r && r.category_id);

if (!rows.length) {
  // Nu există categorii netraduse — semnal "done"
  return [{ json: { _empty: true, marketplace, translated: 0, failed: 0 } }];
}

const results = [];
let translated = 0;
let failed = 0;

for (const row of rows) {
  const categoryId = String(row.category_id);
  const categoryName = String(row.category_name || '').trim();
  if (!categoryName) { failed++; continue; }

  const result = await translateOne(categoryName);
  if (result.ok) {
    results.push({
      marketplace,
      category_id: categoryId,
      category_name: categoryName,
      name_ro: result.name_ro
    });
    translated++;
  } else {
    failed++;
  }

  // Rate limit: spacing între requesturi
  if (REQUEST_DELAY_MS > 0) {
    await new Promise(r => setTimeout(r, REQUEST_DELAY_MS));
  }
}

// Atașăm summary-ul la primul item, pentru recuperare în nodul final
if (results.length > 0) {
  results[0]._summary = { marketplace, translated, failed, total: rows.length };
  return results.map(r => ({ json: r }));
}

return [{ json: { _empty: true, marketplace, translated, failed, total: rows.length } }];

// Formatează răspunsul final: contorizează succese și eșecuri
const items = $('Translate Loop').all().map(i => i.json);
const first = items[0] || {};
const summary = first._summary || { marketplace: first.marketplace || null, translated: 0, failed: 0, total: 0 };

// Rulăm un query suplimentar pentru a obține remaining-ul
return [{
  json: {
    marketplace: summary.marketplace,
    translated: summary.translated || items.filter(i => i.name_ro && !i._empty).length,
    failed: summary.failed || 0,
    batch_size: summary.total || items.length
  }
}];
